import{_ as i,o as t,c as s,ag as a}from"./chunks/framework.BDReElpY.js";const k=JSON.parse('{"title":"Expressions and Operators","description":"","frontmatter":{"layout":"doc","title":"Expressions and Operators"},"headers":[],"relativePath":"hdl/expressions-operators.md","filePath":"hdl/expressions-operators.md"}'),l={name:"hdl/expressions-operators.md"};function o(n,e,d,r,h,c){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="vexhdl-expressions-and-operators-guide" tabindex="-1">VexHDL Expressions and Operators Guide <a class="header-anchor" href="#vexhdl-expressions-and-operators-guide" aria-label="Permalink to &quot;VexHDL Expressions and Operators Guide&quot;">​</a></h1><p>This guide details VexHDL&#39;s expression syntax, binary/unary operators, bit slicing/concatenation, and built-in namespace functions.</p><hr><h2 id="_1-number-literals" tabindex="-1">1. Number Literals <a class="header-anchor" href="#_1-number-literals" aria-label="Permalink to &quot;1. Number Literals&quot;">​</a></h2><p>VexHDL supports flexible integer and bit-vector literals:</p><ul><li><strong>Simple Integers</strong>: Decimal numbers (e.g. <code>42</code>, <code>1000</code>).</li><li><strong>Radix-Based Literals</strong>: Formatted as <code>&lt;width&gt;&#39;&lt;radix&gt;&lt;value&gt;</code>. Radixes include binary (<code>b</code>), octal (<code>o</code>), decimal (<code>d</code>), and hexadecimal (<code>h</code>). <ul><li><code>8&#39;hFF</code>: 8-bit hex literal representing <code>255</code>.</li><li><code>16&#39;d450</code>: 16-bit decimal literal.</li></ul></li><li><strong>4-State Literals (Z &amp; X)</strong>: Radix literals can contain <code>x</code>/<code>X</code> (unknown) and <code>z</code>/<code>Z</code> (high impedance) characters. <ul><li><code>4&#39;b10z1</code>: 4-bit literal containing <code>1</code>, <code>0</code>, <code>Z</code>, <code>1</code> states.</li><li><code>8&#39;b00xx_zzzz</code>: 8-bit literal with lower bits high-impedance and middle bits unknown.</li></ul></li></ul><hr><h2 id="_2-operators" tabindex="-1">2. Operators <a class="header-anchor" href="#_2-operators" aria-label="Permalink to &quot;2. Operators&quot;">​</a></h2><h3 id="_2-1-unary-operators" tabindex="-1">2.1 Unary Operators <a class="header-anchor" href="#_2-1-unary-operators" aria-label="Permalink to &quot;2.1 Unary Operators&quot;">​</a></h3><p>Unary operators operate on a single operand:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Description</th><th style="text-align:left;">Example</th></tr></thead><tbody><tr><td style="text-align:left;"><code>~</code></td><td style="text-align:left;">Bitwise Not</td><td style="text-align:left;">Flips every bit of the operand</td><td style="text-align:left;"><code>let mask = ~4&#39;b1010; // 4&#39;b0101</code></td></tr><tr><td style="text-align:left;"><code>!</code></td><td style="text-align:left;">Logical Not</td><td style="text-align:left;">Inverts boolean state</td><td style="text-align:left;"><code>let is_false = !is_true;</code></td></tr><tr><td style="text-align:left;"><code>-</code></td><td style="text-align:left;">Arithmetic Negation</td><td style="text-align:left;">Inverts sign of the number (2&#39;s complement)</td><td style="text-align:left;"><code>let negative_v = -data_in;</code></td></tr><tr><td style="text-align:left;"><code>&amp;</code></td><td style="text-align:left;">And-Reduction</td><td style="text-align:left;">Performs bitwise AND across all bits of the operand</td><td style="text-align:left;"><code>let all_ones = &amp;byte_val;</code></td></tr><tr><td style="text-align:left;"><code>|</code></td><td style="text-align:left;">Or-Reduction</td><td style="text-align:left;">Performs bitwise OR across all bits of the operand</td><td style="text-align:left;"><code>let has_one = |byte_val;</code></td></tr><tr><td style="text-align:left;"><code>^</code></td><td style="text-align:left;">Xor-Reduction</td><td style="text-align:left;">Performs bitwise XOR across all bits (parity check)</td><td style="text-align:left;"><code>let parity = ^byte_val;</code></td></tr></tbody></table><h3 id="_2-2-binary-operators" tabindex="-1">2.2 Binary Operators <a class="header-anchor" href="#_2-2-binary-operators" aria-label="Permalink to &quot;2.2 Binary Operators&quot;">​</a></h3><p>Binary operators operate on two operands:</p><ul><li><strong>Arithmetic</strong>: Addition <code>+</code>, Subtraction <code>-</code>, Multiplication <code>*</code>, Division <code>/</code>, Modulo <code>%</code>.</li><li><strong>Bitwise Logic</strong>: Bitwise And <code>&amp;</code>, Bitwise Or <code>|</code>, Bitwise Xor <code>^</code>.</li><li><strong>Logical</strong>: Logic And <code>&amp;&amp;</code>, Logic Or <code>||</code>.</li><li><strong>Shifting</strong>: <ul><li>Logical Left-Shift <code>&lt;&lt;</code> (fills with <code>0</code>).</li><li>Logical Right-Shift <code>&gt;&gt;</code> (fills with <code>0</code>).</li><li>Arithmetic Right-Shift <code>&gt;&gt;&gt;</code> (preserves sign bit).</li></ul></li><li><strong>Comparisons</strong>: <ul><li>Inequalities: <code>&lt;</code>, <code>&lt;=</code>, <code>&gt;</code>, <code>&gt;=</code>.</li><li>Equality: <code>==</code> (equality check, propagates <code>X/Z</code>), <code>!=</code> (inequality check).</li><li>Case Equality: <code>===</code> (strict equality comparison of <code>0</code>, <code>1</code>, <code>X</code>, and <code>Z</code> bits without propagation), <code>!==</code> (strict inequality).</li></ul></li></ul><h3 id="_2-3-ternary-operator" tabindex="-1">2.3 Ternary Operator <a class="header-anchor" href="#_2-3-ternary-operator" aria-label="Permalink to &quot;2.3 Ternary Operator&quot;">​</a></h3><p>Conditional selector:</p><div class="language-vexhdl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vexhdl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> result</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> U</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;8&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> select_flag </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> val_a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> val_b;</span></span></code></pre></div><hr><h2 id="_3-bit-manipulation" tabindex="-1">3. Bit Manipulation <a class="header-anchor" href="#_3-bit-manipulation" aria-label="Permalink to &quot;3. Bit Manipulation&quot;">​</a></h2><ul><li><strong>Bit Selection</strong>: Extracts a single bit from a bus.<div class="language-vexhdl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vexhdl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> lsb</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Bool</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> data_bus[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span></code></pre></div></li><li><strong>Bit Slicing (Part-Select)</strong>: Extracts a sub-bus slice using <code>[msb:lsb]</code> syntax.<div class="language-vexhdl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vexhdl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> upper_nibble</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> U</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;4&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> data_bus[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span></code></pre></div></li><li><strong>Concatenation</strong>: Chains multiple signals into a single bus using <code>{a, b, ...}</code> syntax.<div class="language-vexhdl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vexhdl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> combined_bus</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> U</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;8&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {upper_nibble, lower_nibble};</span></span></code></pre></div></li><li><strong>Replication</strong>: Repeats a signal <code>N</code> times using <code>{N{expr}}</code> syntax.<div class="language-vexhdl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vexhdl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> clear_vector</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> U</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;8&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}}; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 8&#39;b0000_0000</span></span></code></pre></div></li></ul><hr><h2 id="_4-built-in-namespaces" tabindex="-1">4. Built-in Namespaces <a class="header-anchor" href="#_4-built-in-namespaces" aria-label="Permalink to &quot;4. Built-in Namespaces&quot;">​</a></h2><p>VexHDL provides standard helper functions organized inside static namespaces:</p><h3 id="_4-1-sim-simulation-only" tabindex="-1">4.1 <code>Sim</code> (Simulation Only) <a class="header-anchor" href="#_4-1-sim-simulation-only" aria-label="Permalink to &quot;4.1 `Sim` (Simulation Only)&quot;">​</a></h3><ul><li><code>Sim.delay(ticks)</code>: Halts execution of the calling thread for <code>ticks</code> simulation steps.</li><li><code>Sim.print(format, args...)</code>: Prints formatted messages to Tauri Studio&#39;s output terminal (supports <code>%d</code>, <code>%h</code>, <code>%b</code>).</li><li><code>Sim.assert(condition, message)</code>: Verifies runtime condition; raises simulation error on failure.</li><li><code>Sim.finish()</code>: Stops simulation runner.</li></ul><h3 id="_4-2-math-compile-time-elaboration" tabindex="-1">4.2 <code>Math</code> (Compile-time Elaboration) <a class="header-anchor" href="#_4-2-math-compile-time-elaboration" aria-label="Permalink to &quot;4.2 `Math` (Compile-time Elaboration)&quot;">​</a></h3><ul><li><code>Math.clog2(val)</code>: Calculates ceiling log2 of <code>val</code> (useful for calculating address widths from memory depth).<div class="language-vexhdl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vexhdl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">param </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ADDR_WIDTH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> U</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;32&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Math</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clog2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1024</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Evaluates to 10</span></span></code></pre></div></li></ul><h3 id="_4-3-bit-gate-hardware-primitives" tabindex="-1">4.3 <code>Bit</code> &amp; <code>Gate</code> (Hardware Primitives) <a class="header-anchor" href="#_4-3-bit-gate-hardware-primitives" aria-label="Permalink to &quot;4.3 `Bit` &amp; `Gate` (Hardware Primitives)&quot;">​</a></h3><ul><li><code>Gate</code> namespace exposes cell-level logic gate primitives for netlist structures (e.g. <code>Gate.and(a, b)</code>).</li></ul><h3 id="_4-4-mem-memory-access" tabindex="-1">4.4 <code>Mem</code> (Memory Access) <a class="header-anchor" href="#_4-4-mem-memory-access" aria-label="Permalink to &quot;4.4 `Mem` (Memory Access)&quot;">​</a></h3><ul><li>Exposes primitives for writing to and reading from <code>Reg</code> memories with specific clock triggers.</li></ul>',31)])])}const g=i(l,[["render",o]]);export{k as __pageData,g as default};
